        <tr>
            <td>${row.number || ''}</td>
            <td>${row.who || ''}</td>
            <td>${row.activity || ''}</td>
        </tr>`;
    }
  });
  tableHTML += `
    </tbody>
</table>`;
  return tableHTML;
}

